class Solution {
public:
    bool canBeEqual(vector<int>& target, vector<int>& arr) {
        int countT[1001] = {0};
        int countA[1001] = {0};

        for (int num : target) {
            countT[num]++;
        }
        for (int num : arr) {
            countA[num]++;
        }

        for (int i = 1; i <= 1000; ++i) {
            if (countT[i] != countA[i]) {
                return false;
            }
        }
        return true;
    }
};

